from dataclasses import dataclass

@dataclass
class Query:
    table: str
    columns: list[str]
    where: list[str]
    limit: int | None = None

    def to_sql(self) -> str:
        cols = ", ".join(self.columns) if self.columns else "*"
        sql = f"SELECT {cols} FROM {self.table}"
        if self.where:
            sql += " WHERE " + " AND ".join(self.where)
        if self.limit is not None:
            sql += f" LIMIT {self.limit}"
        return sql
